package com.restaurantcraft.registry;
import com.restaurantcraft.RestaurantCraft; import com.restaurantcraft.data.DishRegistry; import com.restaurantcraft.item.MopItem; import net.minecraft.world.item.*; import net.minecraft.world.food.FoodProperties; import net.minecraftforge.registries.*; import net.minecraftforge.eventbus.api.IEventBus; import java.util.*;
public class ModItems { public static final DeferredRegister<Item> ITEMS=DeferredRegister.create(ForgeRegistries.ITEMS,RestaurantCraft.MODID); public static final List<RegistryObject<Item>> ALL=new ArrayList<>(); public static final Map<String,RegistryObject<Item>> RECIPE_ITEMS=new LinkedHashMap<>(),RAW_DISH_ITEMS=new LinkedHashMap<>(),COOKED_DISH_ITEMS=new LinkedHashMap<>(); public static final Map<String,RegistryObject<Item>> MATERIALS=new LinkedHashMap<>();
 static { block("restaurant_management_block",ModBlocks.RESTAURANT_MANAGEMENT_BLOCK); block("restaurant_table",ModBlocks.RESTAURANT_TABLE); block("restaurant_chair",ModBlocks.RESTAURANT_CHAIR); block("restaurant_entrance",ModBlocks.RESTAURANT_ENTRANCE); block("restaurant_exit",ModBlocks.RESTAURANT_EXIT); block("steamer",ModBlocks.STEAMER); block("boiling_pot",ModBlocks.BOILING_POT); block("wok",ModBlocks.WOK); block("drink_mixer",ModBlocks.DRINK_MIXER); block("sink",ModBlocks.SINK); block("small_potted_plant_1",ModBlocks.SMALL_POTTED_PLANT_1); block("large_potted_plant_1",ModBlocks.LARGE_POTTED_PLANT_1); block("electric_appliance_1",ModBlocks.ELECTRIC_APPLIANCE_1); block("instrument_1",ModBlocks.INSTRUMENT_1); reg("mop",()->new MopItem(new Item.Properties().stacksTo(1))); for(String m: List.of("salt","white_pepper","pepper_powder","black_pepper_sauce","spicy_sauce","soy_sauce","chili","chrysanthemum","shiitake","milk_bottle")) MATERIALS.put(m, reg(m,()->new Item(new Item.Properties()))); for(var d:DishRegistry.DISHES){ RECIPE_ITEMS.put(d.id(),reg(d.id()+"_recipe",()->new Item(new Item.Properties()))); RAW_DISH_ITEMS.put(d.id(),reg("raw_"+d.id(),()->new Item(new Item.Properties()))); COOKED_DISH_ITEMS.put(d.id(),reg("cooked_"+d.id(),()->new BlockItem(ModBlocks.FOOD_DISPLAY_BLOCKS.get(d.id()).get(), new Item.Properties().food(new FoodProperties.Builder().nutrition(4).saturationMod(0.6f).build())))); } }
 static RegistryObject<Item> reg(String id, java.util.function.Supplier<Item> s){RegistryObject<Item> r=ITEMS.register(id,s); ALL.add(r); return r;} static void block(String id, RegistryObject<? extends net.minecraft.world.level.block.Block> b){reg(id,()->new BlockItem(b.get(),new Item.Properties()));} public static void register(IEventBus bus){ITEMS.register(bus);} }
